import ldap3
from ldap3 import Server, Connection, ALL

def search_user(username):
    # Define server and set up connection
    server = Server('ldap://server_ip', get_info=ALL)
    conn = Connection(server, user='cn=admin,dc=example,dc=com', password='password')
    
    # Connect to LDAP directory
    if not conn.bind():
        print("Error in connection: ", conn.result)
        return
        
    # Define search filter and attributes
    search_filter = f'(sAMAccountName={username})'
    attributes = ['cn', 'mail']
    
    # Execute LDAP search operation
    if not conn.search(search_base='dc=example,dc=com', search_filter=search_filter, attributes=attributes):
        print("Error in search: ", conn.result)
        return
        
    # Print results
    for entry in conn.entries:
        print(f"User {entry['sAMAccountName']} found!")
        print(f"- Full DN: {entry.distinguished_name}")
        if 'cn' in entry.attributes.keys():
            print(f"- Common Name: {entry['cn'][0]}")
        if 'mail' in entry.attributes.keys():
            print(f"- Email Address: {entry['mail'][0]}")